    "long_text": "<div class=\"pz-top\">\r\n<div class=\"pz-top-right\"></div>\r\n<div class=\"pz-top-center\"></div>\r\n<div class=\"pz-top-left\"></div>\r\n</div>\r\n\r\n\t\t\t\r\n\t\t\t\r\n\t\t\t<div id=\"post_message_5012\" class=\"pz-post-content\"><font color=\"#0000CD\"><div style=\"text-align: center;\"><font><font color=\"#cc0000\">- 2 -</font><br>\n<font color=\"#000080\">الإمام المهديّ ناصر محمد اليماني<br>\n02 - شعبان -1430 هـ<br>\n25 - 07- 2009 مـ<br>\n08:43 مساءً<br>\n( بحسب التّقويم الرّسميّ لأمّ القُرَى )<a href=\"https://nasser-alyamani.org/showthread.php?p=1028\" target=\"_blank\" rel=\"nofollow\"><br>\n</a><br>\n<a href=\"https://nasser-alyamani.org/showthread.php?p=1028\" target=\"_blank\" rel=\"nofollow\"><font><font color=\"#000080\">[ لمتابعة رابط المشاركة الأصلية للبيان ]<br>\n</font></font></a><a href=\"https://nasser-alyamani.org/showthread.php?p=1028\" target=\"_blank\" rel=\"nofollow\"><font><font color=\"#000080\">https://nasser-alyamani.org/showthread.php?p=1028<br>\n</font></font></a>___________</font><br>\n<br>\n<br>\n<font color=\"#800080\"><u>لكلِّ اسمٍ مِن أسماءِ الله الحُسْنى بَيانٌ تَجِدونَه الحقّ على الوَاقِع الحَقيقيّ ..</u></font><br>\n<br>\n<br>\n<div class=\"notepaper\">\r\n  <figure class=\"quote\">\r\n    <blockquote class=\"curly-quotes\">\r\n<div class=\"name_of_quote_first\">اقتباس المشاركة  :  \r\n\t\t\t\t\t</div>\r\n\t\t\t\t<font><div style=\"text-align: center;\"><font color=\"#000080\">المشاركة الأصلية كتبت بواسطة احمد شعبان<br>\nتحية مباركة طيبة وبعد، لي سؤال أرجو الإجابة عليه وهو: توضيح العلاقة بين لفظ الجلالة \" الله \" والأسماء الحسنى، ولسيادتكم جزيل شكري. والسلام عليكم ورحمة الله وبركاته.</font></div></font>\r\n</blockquote>\r\n    <figcaption class=\"quote-by\">— \r\n<span class=\"name_of_quote\">انتهى الاقتباس</span>\r\n\t\t\t</figcaption>\r\n  </figure>\r\n</div>\r\n\r\n\r\n<br>\nبِسْمِ <font color=\"#cc0000\">(اللَّـهِ)</font> الرَّحْمَـٰنِ الرَّحِيمِ النّعيم الأعظم في رِضاه وفي ذلك يُوجَدُ البيانُ الحقّ لاسمِ <font color=\"#cc0000\">(الله)</font> سُبحانه وتعالى عُلوًّا كبيرًا، أفلا يَعلَمونَ أنّهم عَبيدٌ <font color=\"#cc0000\">(للَّهِ)</font> الحقّ لعِباده عمّا سِواهُ؟ والذين ألهاهُم - <font color=\"#0000cd\">عن </font><font color=\"#cc0000\">(</font><font color=\"#cc0000\">اللَّهِ الحقّ) </font><font color=\"#0000cd\">- </font>التّكاثُر في الحياةِ الدُّنيا <u>أولئِكَ ما قَدرُوا الله حقّ قَدرِه لأنّهم لم يَعرِفوا <font color=\"#cc0000\">(الله)</font> حقّ مَعرِفَتِه، ولو عرَفُوا حقيقة <font color=\"#cc0000\">(اللَّهِ الحقّ)</font> عمّن سِواهُ لما ألهاهُم عنه أيّ شيءٍ في الوُجودِ كُلّه، ولكنّهم ما عَرفُوا الحقَّ حقّ مَعرِفَتِه ولذلك ألهَاهُم عنه سِواهُ؛ التَّكاثُر في الحياةِ الدُّنيا وزينَتها.</u><br>\n<br>\nذلك خُلاصَة البيانِ لاسْمِ <font color=\"#cc0000\">(الله)</font> تجدوه في قول الله تعالى:<br>\n<font color=\"#006400\">{بِسْمِ اللَّـهِ الرَّحْمَـٰنِ الرَّحِيمِ}</font><br>\n<br>\nأي <font color=\"#cc0000\">(اللَّهِ)</font> الحقّ لعَبِيدِه عمّا سِواهُ؛ <font color=\"#cc0000\">(الرّحمن)</font> على العَرشِ استَوَى أرحمُ الرّاحِمين، فلا يُوجَد شيءٌ في الوُجودِ كلّه هو أرحَم بعبادِه مِن <font color=\"#cc0000\">(اللَّهِ)</font> أرحَم الرّاحمين، فلا يُلهِكُم عن ذِكرِه سِواهُ، فإنّ الذين ألهاهُم عن <font color=\"#cc0000\">(اللَّهِ الحقّ)</font> سِواه فلم يَكن مَحيَاهُم <font color=\"#cc0000\">(للَّهِ)</font> في هذه الحياة ولذلك خلقَهُم ولذلك يُعَذِّبهم عذابًا نُكرًا.<br>\n<br>\n<u>ولكلِّ اسمٍ مِن أسماءِ الله الحُسْنى بيانٌ تَجِدونَه الحقّ على الوَاقِع الحقيقيّ في أنفُسِكم وفيما بين أيديكم في سَماوَاته وأرضِه ولكنّ أكثرَ الناس لا يَشكُرون!<br>\n<br>\n<font color=\"#cc0000\">فهُم لِلّــــــهِ فكيف يَعبُدونَ سِواه؟!</font></u><br>\n<br>\nإِنا للَّـه وإِنَّا إِليه رَاجِعُون؛ سُبحانَ ربِّكَ ربِّ العِزّةِ عمّا يَصِفون.<br>\n<br>\nوسَلامٌ على المُرسَلين؛ والحمدُ لِلّه ربّ العالَمين..<br>\nأخوكُم عبد النّعيم الأعظم؛ الإمام المهديّ ناصر محمد اليماني.<br>\n_____________<br>\n</font></div></font></div>\r\n\t\t\t\r\n\t\t\t\r\n\r\n\t\t\t\r\n\r\n\r\n\r\n\r\n<div class=\"pz-bottom\">\r\n<div class=\"pz-top-right\"></div>\r\n<div class=\"pz-top-center\"></div>\r\n<div class=\"pz-top-left\"></div>\r\n</div>",
